SELECT field_id, COUNT(lookup_value_id) AS lookup_value_count
FROM lookup_values
GROUP BY field_id;

SELECT action, COUNT(*) AS action_count
FROM audit_log
GROUP BY action;

SELECT COUNT(*) AS default_lookup_value_count
FROM lookup_values
WHERE is_default = 1;

SELECT AVG(num_synonyms) AS avg_synonyms_per_value
FROM (
  SELECT lookup_value_id, COUNT(*) AS num_synonyms
  FROM lookup_synonyms
  GROUP BY lookup_value_id
);

SELECT AVG(log_count) AS average_logs_per_user
FROM (
    SELECT user_id, COUNT(*) AS log_count
    FROM audit_log
    GROUP BY user_id
);
